import{_ as t,H as s,f as o,b as n,j as e}from"./chunks/framework.DLd0CbzH.js";const i="/assets/prompt.CDYwYVMC.png",r="/assets/ts.CkOkxq69.png",a="/assets/e_d.DMx8tg0R.png",p="/assets/pe.DfwDto96.png",m="/assets/sa.CHPXJbfr.png",c="/assets/msa.BF6yAvvw.png",u="/assets/fn.cPLRai8c.png",d="/assets/ot.DF6ymmVj.png",g="/assets/zsi.ByCnolZv.png",h="/assets/osi.yMX2Jfro.png",T=JSON.parse('{"title":"LLM大模型（大语言模型）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/llm.md","filePath":"ai/llm.md","lastUpdated":1780151766000}'),f={name:"ai/llm.md"};function _(k,l,P,b,w,x){return s(),o("div",null,[...l[0]||(l[0]=[n("h1",{id:"llm大模型-大语言模型",tabindex:"-1"},[e("LLM大模型（大语言模型） "),n("a",{class:"header-anchor",href:"#llm大模型-大语言模型","aria-label":'Permalink to "LLM大模型（大语言模型）"'},"​")],-1),n("h2",{id:"prompts-and-completions",tabindex:"-1"},[e("Prompts and completions "),n("a",{class:"header-anchor",href:"#prompts-and-completions","aria-label":'Permalink to "Prompts and completions"'},"​")],-1),n("img",{src:i,width:"1544",title:"",crop:"0,0,1,1",id:"u50cd4df0",class:"ne-image"},null,-1),n("p",null,"prompt： 传递给大语言模型的指令文本",-1),n("p",null,"上下文窗口：Prompt可用的空间或记忆，通常足够放下几千个字（每个模型的上下文量不一致）",-1),n("p",null,"Prompt被传递给模型。模型预测下一个词，因为prompt包含了问题，模型就生成了一个答案。",-1),n("p",null,"模型输出被称为完成（Completion），使用模型生成文本的行为被称为推理",-1),n("p",null,"一个流行的应用领域是通过将LLM与外部数据源连接或者调用外部API来对LLM能力进行增强",-1),n("p",null,"早期的语言模型使用的是循环网络神经网络或者RNN架构",-1),n("p",null,"RNN：需要大量计算和内存来执行生成任务，能力被限制",-1),n("p",null,"取代它们的：Transformers框架",-1),n("img",{src:r,width:"635",title:"",crop:"0,0,1,1",id:"u04aa4e84",class:"ne-image"},null,-1),n("ul",null,[n("li",null,"有效地扩展到使用多核GPU"),n("li",null,"可以并行处理输入数据"),n("li",null,"利用更大的训练数据集"),n("li",null,[n("strong",null,"学会关注它正在处理的词的含义")])],-1),n("h3",{id:"transformer架构被分成两个独立的部分-编码器和解码器",tabindex:"-1"},[e("Transformer架构被分成两个独立的部分：编码器和解码器 "),n("a",{class:"header-anchor",href:"#transformer架构被分成两个独立的部分-编码器和解码器","aria-label":'Permalink to "Transformer架构被分成两个独立的部分：编码器和解码器"'},"​")],-1),n("img",{src:a,width:"717",title:"",crop:"0,0,1,1",id:"ub8b1654b",class:"ne-image"},null,-1),n("p",null,"我们在模型输入的时候，使用的是文字也就是单词，在文本被传递给模型处理之前，我们必须将这些文本进行分词，也就是把这些文本变成token，传递给嵌入层，这个是一个可以训练的向量嵌入空间，每一个token都被表示为一个向量，并且在该空间占据一个独特的位置。每一个tokenID都对应一个多维向量，这些向量可以学习编码输入序列中单个token的含义和上下文。",-1),n("p",null,"当token向量前往编码器或者解码器的时候，需要添加上位置编码（Positional Encoding）",-1),n("img",{src:p,width:"1616",title:"",crop:"0,0,1,1",id:"ubc0802a5",class:"ne-image"},null,-1),n("p",null,"位置编码：保留关于输入单词顺序的信息，不会丧失单词在句子中的位置的相关性。",-1),n("p",null,"token和位置编码结合之后得到的结果向量会传递给自注意力层",-1),n("img",{src:m,width:"1311",title:"",crop:"0,0,1,1",id:"u136c5653",class:"ne-image"},null,-1),n("p",null,"在这一层中，模型分析输入序列中Token之间的关系，因为是向量数据，所以模型能够关注输入序列的不同部分，更好得捕捉单词之间的上下文依赖关系。",-1),n("p",null,"在训练期间学习并存储在这些层中的自注意力权重反映了输入序列中每个单词对所有其它单词的重要性。",-1),n("p",null,"Transformer架构具有多头自注意力，所以自注意力并不只是发生一次。也就意味着。多组自注意力权重或被并行、独立的学习",-1),n("img",{src:c,width:"1493",title:"",crop:"0,0,1,1",id:"u04f839e8",class:"ne-image"},null,-1),n("p",null,"每个权重都是随机初始化的，给定足够的训练数据和时间，每个自注意力都将学习到不同的方面。",-1),n("p",null,"接下来注意力权重会应用到输入数据上，输出被处理通过一个全连接的前向网络。这一层的输出是一个对数向量，与Tokenizer字典中的每一个Token的概率分数成比例。",-1),n("img",{src:u,width:"1577",title:"",crop:"0,0,1,1",id:"u97543d66",class:"ne-image"},null,-1),n("p",null,"这些对数会被传递给最后的Softmax层，它们被归一化为每个单词的概率分数。",-1),n("img",{src:d,width:"1554",title:"",crop:"0,0,1,1",id:"u139594ed",class:"ne-image"},null,-1),n("p",null,"这个输出会包含词汇表中每个单词的概率，可能会有成千上万个分数，每一个单独的token都会有一个比较高的概率分数高于其余部分，这就是最有可能预测的Token，当然最后的组成是可以通过方法变更的，后面会讲到",-1),n("p",null,"编码器：将输入序列编码为输入的结构和含义的深层表示",-1),n("p",null,"解码器：从输入Token触发器开始工作，使用编码器的上下文理解生成新的token",-1),n("p",null,"它们以循环的方式进行，直到达到某个停止条件。",-1),n("h3",{id:"prompt-engineering-提示工程",tabindex:"-1"},[e("Prompt Engineering 提示工程 "),n("a",{class:"header-anchor",href:"#prompt-engineering-提示工程","aria-label":'Permalink to "Prompt Engineering 提示工程"'},"​")],-1),n("p",null,"输入到模型中的文本被称为Prompt，生成文本的动作被称为推断（Inference），输出的文本被称为完成（Completion），全文或者可用于Prompt的记忆被称为上下文窗口（Context Window）。",-1),n("p",null,"如下图所示，将输入数据包含在prompt中，被称为零样例推断（Zero-shot Inference）",-1),n("img",{src:g,width:"1631",title:"",crop:"0,0,1,1",id:"u9471bc4a",class:"ne-image"},null,-1),n("p",null,"如下图所示，包含单个样例的方法被称为单样例推断（One-shot Inference）",-1),n("img",{src:h,width:"1545",title:"",crop:"0,0,1,1",id:"ua508889a",class:"ne-image"},null,-1),n("p",null,"当然我们还可以输入多个样例，那就是少样例推断（Few-shot Inference）。如果说，我们在输入了五六个样例模型的返回结果还是不理想的话，就需要对模型进行微调（Fine-tuning）",-1)])])}const C=t(f,[["render",_]]);export{T as __pageData,C as default};
